import { mkdir, writeFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import { applyProject } from './apply.js';
import { loadBrowserConfig } from './config/load.js';
import { generateMozconfig } from './firefox/mozconfig.js';
import { readFirefoxLock } from './source.js';
import { projectPaths } from './project.js';
export async function prepareProject(cwd = process.cwd()) {
    const [config, lock] = await Promise.all([loadBrowserConfig(cwd), readFirefoxLock(cwd)]);
    const paths = await projectPaths(cwd);
    await writeFile(resolve(cwd, 'mozconfig'), generateMozconfig(config, lock.version));
    await mkdir(resolve(paths.firefoxSource, `obj-geckokit-${config.browser.binaryName}`), { recursive: true });
    await applyProject(cwd);
}
